import SideCart from '@/components/SideCart.vue'

export default {
  name: 'App',
  data () {
    return {
      searchShow: false,
      sidenavShow: false,
      saleShow: false,
      topShow: false,
      bottomShow: false,
      onePieceShow: false,
      homeWearShow: false,
      accessoryShow: false,
      cartShow: false,
      inventory: {
        id: 0,
        color: '',
        size: '',
        qty: 0
      }
    }
  },
  methods: {
    check (newinput) {
      var flag = -1
      this.cart.forEach(i => {
        if (i.color === newinput.color && i.size === newinput.size) {
          flag = i.id
        }
      })
      return flag
    },
    addToCart () {
      this.total += this.inventory.qty
      var cartindex = this.check(this.inventory)
      if (cartindex !== -1) {
        this.cart[cartindex].qty = this.cart[cartindex].qty + this.inventory.qty
      } else {
        var temp = { id: 0, color: '', qty: 0, size: '' }
        temp.id = this.inventory.id
        temp.color = 'img/new-in/top/top-' + this.inventory.color + '.jpg'
        temp.qty = this.inventory.qty
        temp.size = this.inventory.size
        this.cart.push(temp)
        this.inventory.id++
      }
      this.inventory.qty = 0
      this.cart.forEach(element => {
        console.log(element)
      })
    }
    // removeItem (indexRemove) {
    //   var removeItem = $.map(this.cart, function (item) {
    //     return item.id
    //   }).indexOf(indexRemove);
    //   this.total -= this.cart[removeItem].qty
    //   this.cart.splice(removeItem, 1)
    // }
  },
  components: {
    SideCart
  }
}
